@objc open func getMaximumEntrySize(withFont font: NSUIFont) -> CGSize
{
    var maxW = CGFloat(0.0)
    var maxH = CGFloat(0.0)
    var maxFormSize: CGFloat = 0.0

    for entry in entries
    {
        let formSize = entry.formSize.isNaN ? self.formSize : entry.formSize
        if formSize > maxFormSize { maxFormSize = formSize }

        guard let label = entry.label else { continue }

        let size = (label as NSString).size(withAttributes: [.font: font])  // ← КАЖДЫЙ РАЗ

        if size.width > maxW { maxW = size.width }
        if size.height > maxH { maxH = size.height }
    }

    return CGSize(width: maxW + maxFormSize + formToTextSpace, height: maxH)
}
